// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract ERPLedger {

    // ── Enums ──
    enum RecordType { STOCK_MOVE, SALES_ORDER, PURCHASE_ORDER, MANUFACTURING_ORDER, DELIVERY, GRN }
    enum Status { CREATED, CONFIRMED, IN_PROGRESS, COMPLETED, CANCELLED }

    // ── Structs ──
    struct ERPRecord {
        uint256 id;
        RecordType recordType;
        string referenceNumber;   // e.g. SO-2024-00001
        string dataHash;          // SHA-256 hash of the full record JSON
        address recordedBy;       // wallet address of the user
        uint256 timestamp;
        Status status;
        string metadata;          // JSON string with key fields
    }

    struct StatusUpdate {
        uint256 recordId;
        Status oldStatus;
        Status newStatus;
        string reason;
        address updatedBy;
        uint256 timestamp;
    }

    // ── State ──
    uint256 private _recordCount;
    mapping(uint256 => ERPRecord) public records;
    mapping(string => uint256) public referenceToId;   // referenceNumber → id
    mapping(uint256 => StatusUpdate[]) public statusHistory;
    mapping(address => bool) public authorizedWriters;
    address public owner;

    // ── Events ──
    event RecordCreated(uint256 indexed id, RecordType recordType, string referenceNumber, string dataHash, uint256 timestamp);
    event StatusUpdated(uint256 indexed recordId, Status oldStatus, Status newStatus, address updatedBy, uint256 timestamp);
    event WriterAuthorized(address writer, bool status);

    // ── Modifiers ──
    modifier onlyOwner() { require(msg.sender == owner, "Not owner"); _; }
    modifier onlyWriter() { require(authorizedWriters[msg.sender] || msg.sender == owner, "Not authorized"); _; }

    constructor() { owner = msg.sender; authorizedWriters[msg.sender] = true; }

    // ── Write Functions ──
    function createRecord(
        RecordType _type,
        string memory _referenceNumber,
        string memory _dataHash,
        string memory _metadata
    ) external onlyWriter returns (uint256) {
        require(referenceToId[_referenceNumber] == 0, "Reference already exists");
        _recordCount++;
        uint256 newId = _recordCount;
        records[newId] = ERPRecord(newId, _type, _referenceNumber, _dataHash, msg.sender, block.timestamp, Status.CREATED, _metadata);
        referenceToId[_referenceNumber] = newId;
        emit RecordCreated(newId, _type, _referenceNumber, _dataHash, block.timestamp);
        return newId;
    }

    function updateStatus(
        uint256 _recordId,
        Status _newStatus,
        string memory _reason
    ) external onlyWriter {
        require(_recordId > 0 && _recordId <= _recordCount, "Invalid record");
        ERPRecord storage record = records[_recordId];
        Status oldStatus = record.status;
        record.status = _newStatus;
        statusHistory[_recordId].push(StatusUpdate(_recordId, oldStatus, _newStatus, _reason, msg.sender, block.timestamp));
        emit StatusUpdated(_recordId, oldStatus, _newStatus, msg.sender, block.timestamp);
    }

    function authorizeWriter(address _writer, bool _status) external onlyOwner {
        authorizedWriters[_writer] = _status;
        emit WriterAuthorized(_writer, _status);
    }

    // ── Read Functions ──
    function getRecord(uint256 _id) external view returns (ERPRecord memory) { return records[_id]; }
    function getRecordByReference(string memory _ref) external view returns (ERPRecord memory) { return records[referenceToId[_ref]]; }
    function getStatusHistory(uint256 _id) external view returns (StatusUpdate[] memory) { return statusHistory[_id]; }
    function getTotalRecords() external view returns (uint256) { return _recordCount; }
    function verifyDataHash(uint256 _id, string memory _hash) external view returns (bool) {
        return keccak256(bytes(records[_id].dataHash)) == keccak256(bytes(_hash));
    }
}

contracts/StockVerifier.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract StockVerifier {
    struct StockEntry {
        string moveReference;
        string productCode;
        string fromLocation;
        string toLocation;
        uint256 quantity;        // quantity * 1000 to avoid decimals
        string uom;
        string dataHash;
        address recordedBy;
        uint256 timestamp;
        string moveType;         // sale/purchase/manufacturing/adjustment
    }

    uint256 private _entryCount;
    mapping(uint256 => StockEntry) public entries;
    mapping(string => uint256[]) public productHistory;  // productCode → entry ids
    mapping(address => bool) public authorizedWriters;
    address public owner;

    event StockMoveRecorded(uint256 id, string productCode, uint256 quantity, string moveType, uint256 timestamp);
    event WriterAuthorized(address writer, bool status);

    modifier onlyOwner() { require(msg.sender == owner, "Not owner"); _; }
    modifier onlyWriter() { require(authorizedWriters[msg.sender] || msg.sender == owner, "Not authorized"); _; }

    constructor() { owner = msg.sender; authorizedWriters[msg.sender] = true; }

    function recordStockMove(
        string memory _moveReference,
        string memory _productCode,
        string memory _fromLocation,
        string memory _toLocation,
        uint256 _quantity,
        string memory _uom,
        string memory _dataHash,
        string memory _moveType
    ) external onlyWriter returns (uint256) {
        _entryCount++;
        uint256 newId = _entryCount;

        entries[newId] = StockEntry(
            _moveReference,
            _productCode,
            _fromLocation,
            _toLocation,
            _quantity,
            _uom,
            _dataHash,
            msg.sender,
            block.timestamp,
            _moveType
        );

        productHistory[_productCode].push(newId);

        emit StockMoveRecorded(newId, _productCode, _quantity, _moveType, block.timestamp);
        return newId;
    }

    function authorizeWriter(address _writer, bool _status) external onlyOwner {
        authorizedWriters[_writer] = _status;
        emit WriterAuthorized(_writer, _status);
    }

    function getProductHistory(string memory productCode) external view returns (StockEntry[] memory) {
        uint256[] memory ids = productHistory[productCode];
        StockEntry[] memory history = new StockEntry[](ids.length);
        for(uint i = 0; i < ids.length; i++) {
            history[i] = entries[ids[i]];
        }
        return history;
    }

    function getTotalMovesForProduct(string memory productCode) external view returns (uint256) {
        return productHistory[productCode].length;
    }
}

contracts/SyncraAuditTrail.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title SyncraAuditTrail
 * @dev Immutable audit layer for Syncra ERP inventory traceability
 * Used ONLY for audit logs, stock verification, and procurement/manufacturing proof
 */
contract SyncraAuditTrail {
    struct AuditRecord {
        bytes32 id;
        string eventType;
        string entityType;
        string entityId;
        string dataHash;
        address recorder;
        uint256 timestamp;
        bool verified;
    }

    mapping(bytes32 => AuditRecord) public records;
    bytes32[] public recordIds;

    uint256 public totalRecords;
    address public owner;

    event AuditRecorded(
        bytes32 indexed recordId,
        string eventType,
        string entityType,
        string entityId,
        string dataHash,
        address recorder,
        uint256 timestamp
    );

    event RecordVerified(bytes32 indexed recordId, bool verified);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not authorized");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function recordAudit(
        string calldata eventType,
        string calldata entityType,
        string calldata entityId,
        string calldata dataHash
    ) external returns (bytes32) {
        bytes32 recordId = keccak256(
            abi.encodePacked(eventType, entityType, entityId, dataHash, block.timestamp, msg.sender)
        );

        records[recordId] = AuditRecord({
            id: recordId,
            eventType: eventType,
            entityType: entityType,
            entityId: entityId,
            dataHash: dataHash,
            recorder: msg.sender,
            timestamp: block.timestamp,
            verified: true
        });

        recordIds.push(recordId);
        totalRecords++;

        emit AuditRecorded(recordId, eventType, entityType, entityId, dataHash, msg.sender, block.timestamp);

        return recordId;
    }

    function verifyRecord(bytes32 recordId) external view returns (bool) {
        return records[recordId].verified && records[recordId].timestamp > 0;
    }

    function getRecord(bytes32 recordId) external view returns (AuditRecord memory) {
        return records[recordId];
    }

    function getRecordCount() external view returns (uint256) {
        return recordIds.length;
    }

    function getRecentRecords(uint256 count) external view returns (AuditRecord[] memory) {
        uint256 length = count > recordIds.length ? recordIds.length : count;
        AuditRecord[] memory recent = new AuditRecord[](length);

        for (uint256 i = 0; i < length; i++) {
            recent[i] = records[recordIds[recordIds.length - 1 - i]];
        }

        return recent;
    }

    function transferOwnership(address newOwner) external onlyOwner {
        require(newOwner != address(0), "Invalid address");
        owner = newOwner;
    }
}

